using Microsoft.AspNetCore.Mvc;
using Microsoft.AspNetCore.Hosting;
using System.IO;
using Microsoft.AspNetCore.StaticFiles;

namespace YourNamespace.Controllers
{
    [ApiController]
    [Route("[controller]")]
    public class FilesController : ControllerBase
    {
        private readonly IWebHostEnvironment _hostingEnvironment;
        private readonly FileExtensionContentTypeProvider _contentTypeProvider;

        public FilesController(IWebHostEnvironment hostingEnvironment)
        {
            _hostingEnvironment = hostingEnvironment;
            _contentTypeProvider = new FileExtensionContentTypeProvider();
        }

        [HttpGet("uploads/{filename}")]
        public IActionResult GetUploadFile(string filename)
        {
            if (string.IsNullOrEmpty(filename))
            {
                return BadRequest("Filename cannot be empty.");
            }

            // Path to the uploads folder
            // Ensure this folder exists and is accessible
            // For production, consider storing uploads outside the wwwroot for better security/management
            // but for a simple example, a subfolder is fine.
            var uploadsFolderPath = Path.Combine(_hostingEnvironment.ContentRootPath, "uploads");
            var filePath = Path.Combine(uploadsFolderPath, filename);

            if (!System.IO.File.Exists(filePath))
            {
                return NotFound($"File '{filename}' not found.");
            }

            // Determine content type
            if (!_contentTypeProvider.TryGetContentType(filename, out var contentType))
            {
                contentType = "application/octet-stream"; // Default generic binary if type cannot be determined
            }

            var fileStream = new FileStream(filePath, FileMode.Open, FileAccess.Read);
            return File(fileStream, contentType);
        }
    }
}